#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 50
#define MAX_M 100
#define MAX_DENOM 30

// Function to calculate the greatest common divisor
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

// Function to simplify a fraction
void simplify(int *num, int *denom) {
    int g = gcd(*num, *denom);
    *num /= g;
    *denom /= g;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int edges[M][3];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d/%d", &edges[i][0], &edges[i][1], &edges[i][2], &edges[i][3]);
            simplify(&edges[i][2], &edges[i][3]);
        }
        // Check the first condition
        int sum = 0;
        for (int i = 0; i < M; i++) {
            sum += edges[i][2];
        }
        if (sum != N - 1) {
            printf("1\n");
            continue;
        }
        // Check the second condition
        for (int mask = 1; mask < (1 << N); mask++) {
            int subset_sum = 0;
            for (int i = 0; i < M; i++) {
                if ((mask & (1 << (edges[i][0] - 1))) && (mask & (1 << (edges[i][1] - 1)))) {
                    subset_sum += edges[i][2];
                }
            }
            int subset_size = 0;
            for (int i = 0; i < N; i++) {
                if (mask & (1 << i)) subset_size++;
            }
            if (subset_sum > subset_size - 1) {
                printf("2\n");
                printf("%d\n", subset_size);
                for (int i = 0; i < N; i++) {
                    if (mask & (1 << i)) printf("%d ", i + 1);
                }
                printf("\n");
                break;
            }
        }
        if (mask == (1 << N)) printf("GST\n");
    }
    return 0;
}

